__global__ void vector_add(float* out, const float* a, const float* b, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < n) out[idx] = a[idx] + b[idx];
}

void launch_vector_add(float* out, const float* a, const float* b, int n) {
    const int block_size = 256;  // Multiple of warp size (32)
    const int grid_size = (n + block_size - 1) / block_size;

    vector_add<<<grid_size, block_size, 0, cudaStreamDefault>>>(out, a, b, n);

    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        printf("CUDA kernel launch error: %s\n", cudaGetErrorString(err));
    }
}

